<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cron</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;0 0 * * *&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 每天UTC 0点执行，对应北京时间早上8点</span></span>
